)

func TestCompactDiffFormatter_Format(t *testing.T) {
	tests := map[string]struct {
		plan  *plans.Plan
		want  string
	}{
		"nil plan": {
			plan: nil,
			want: "",
		},
		"empty plan": {
			plan: &plans.Plan{
				Changes: &plans.Changes{},
			},
			want: "",
		},
		"single create": {
			plan: &plans.Plan{
				Changes: &plans.Changes{
					Resources: []*plans.ResourceInstanceChange{
						{
