func TestCompactDiffFormatter_ActionSymbol(t *testing.T) {
	tests := map[string]struct {
		action plans.Action
		want   string
	}{
		"create": {
			action: plans.Create,
			want:   "+",
		},
		"update": {
			action: plans.Update,
			want:   "~",
		},
		"delete": {
			action: plans.Delete,
			want:   "-",
		},
		"replace (delete then create)": {
			action: plans.DeleteThenCreate,
			want:   "±",
		},
		"replace (create then delete)": {
			action: plans.CreateThenDelete,
			want:   "∓",
		},
		"read": {
			action: plans.Read,
			want:   "<=",
		},
		"forget": {
			action: plans.Forget,
			want:   ".",
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := actionSymbol(tc.action)
			if tc.want != got {
				t.Errorf("actionSymbol(%v) = %q, want %q", tc.action, got, tc.want)
			}
		})
	}
}

