func TestCompactDiffFormatter_SummarizeCounts(t *testing.T) {
	tests := map[string]struct {
		groups map[plans.Action][]string
		want   string
	}{
		"no changes": {
			groups: map[plans.Action][]string{},
			want:   "Plan: No changes.",
		},
		"only creates": {
			groups: map[plans.Action][]string{
				plans.Create: {"aws_instance.a", "aws_instance.b"},
			},
			want: "Plan: 2 to create.",
		},
		"mixed changes": {
			groups: map[plans.Action][]string{
				plans.Create:           {"aws_instance.a"},
				plans.Update:           {"aws_security_group.b", "aws_security_group.c"},
				plans.Delete:           {"aws_key_pair.d"},
				plans.DeleteThenCreate: {"aws_instance.e"},
			},
			want: "Plan: 1 to create, 2 to update, 1 to delete, 1 to replace.",
		},
	}

	formatter := &CompactDiffFormatter{}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.summarizeCounts(tc.groups)
			if tc.want != got {
				t.Errorf("summarizeCounts() = %q, want %q", got, tc.want)
			}
		})
	}
}
